const ctx = $input.first().json;
const webhook = $('Webhook generate-reply').first().json.body;
const email = ctx.email || {};
const client = ctx.client;
const recentEmails = ctx.recentEmails || [];
const openTasks = ctx.openTasks || [];
const instructions = webhook.instructions || '';

const parts = [
  'Tu es assistant du cabinet GargarineV1, courtier en assurances.',
  'Redige une reponse professionnelle a cet email.',
  '',
  'EMAIL RECU :',
  'De: ' + (email.expediteur || 'inconnu'),
  'Objet: ' + (email.sujet || 'Sans objet'),
  '---',
  email.extrait || '(pas de contenu)',
];

if (client) {
  parts.push('', 'CONTEXTE CLIENT :', 'Nom: ' + client.raisonSociale, 'Statut: ' + client.statut);
  if (client.contrats?.length) parts.push('Contrats: ' + client.contrats.map(c => c.typeProduit + ' (' + c.statut + ')').join(', '));
  if (client.deals?.length) parts.push('Deals: ' + client.deals.map(d => d.titre).join(', '));
}

if (recentEmails.length > 0) {
  parts.push('', 'HISTORIQUE RECENT DU FIL :');
  recentEmails.forEach(e => parts.push('[' + e.direction + '] ' + e.sujet + ' — ' + (e.extrait || '').substring(0, 100)));
}

if (openTasks.length > 0) {
  parts.push('', 'TACHES EN COURS :');
  openTasks.forEach(t => parts.push('- ' + t.titre + ' (' + t.type + ', echeance: ' + t.dateEcheance + ')'));
}

if (instructions) {
  parts.push('', 'INSTRUCTIONS SPECIFIQUES :', instructions);
}

parts.push('', 'Redige une reponse concise et professionnelle.');
parts.push('Commence par Bonjour [nom], et termine par Cordialement, GargarineV1 — Courtage en assurances.');

return [{ json: { prompt: parts.join('
') } }];

const geminiRes = $input.first().json;
const rawText = geminiRes.candidates?.[0]?.content?.parts?.[0]?.text || '';
return [{ json: { draftReply: rawText.trim(), model: 'gemini-2.0-flash' } }];
